// components/schedule/ScheduleCanvas.tsx
import { DeckGL } from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';
import { RectangleLayer, TextLayer } from '@deck.gl/layers';

interface ScheduleCanvasProps {
  trains: Train[];
  events: MaintenanceEvent[];
  dateRange: DateRange;
}

export function ScheduleCanvas({ trains, events, dateRange }: ScheduleCanvasProps) {
  const view = new OrthographicView({
    flipY: false,
  });

  const layers = [
    new RectangleLayer({
      id: 'maintenance-blocks',
      data: events,
      getPosition: d => [dateToX(d.startDate), trainToY(d.trainId)],
      getSize: d => [durationToWidth(d), ROW_HEIGHT],
      getFillColor: d => maintenanceColor(d.type),
      pickable: true,
      onHover: handleHover,
    }),
    new TextLayer({
      id: 'train-labels',
      data: trains,
      getPosition: d => [0, trainToY(d.id)],
      getText: d => d.trainId,
      getSize: 12,
      getColor: [255, 255, 255],
    }),
  ];

  return (
    <DeckGL
      views={view}
      layers={layers}
      controller={true}
      width="100%"
      height="100%"
    />
  );
}
